import React, { useState, useRef } from 'react';
import { useSelector } from 'react-redux';
import { studentAPI } from '../services/api';
import toast from 'react-hot-toast';

const CARD_STYLES = [
  { id:'blue',   name:'Classic Blue',   sidebar:'#1E1B4B', accent:'#7C3AED', bg:'#EDE9F8' },
  { id:'green',  name:'Forest Green',   sidebar:'#065F46', accent:'#10B981', bg:'#D1FAE5' },
  { id:'red',    name:'Royal Red',      sidebar:'#991B1B', accent:'#EF4444', bg:'#FEE2E2' },
  { id:'orange', name:'Sunset Orange',  sidebar:'#92400E', accent:'#F59E0B', bg:'#FEF3C7' },
];

function IDCardPreview({ student, settings, style }) {
  var school = settings || {};
  var s = CARD_STYLES.find(function(c) { return c.id === style; }) || CARD_STYLES[0];
  var name = student ? ((student.first_name||'') + ' ' + (student.last_name||'')).trim() : 'Student Name';

  return React.createElement('div', {
    style:{
      width:340, height:200, borderRadius:14, overflow:'hidden',
      boxShadow:'0 8px 32px rgba(0,0,0,.2)', display:'flex',
      fontFamily:'Plus Jakarta Sans, sans-serif', background:'#fff',
      border: '1px solid #E5E7EB',
    }
  },
    // Left sidebar
    React.createElement('div', {
      style:{ width:90, background:s.sidebar, display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', padding:'12px 8px', flexShrink:0 }
    },
      React.createElement('div', {
        style:{ width:62, height:62, borderRadius:10, background:'#fff', overflow:'hidden', marginBottom:8, border:'2px solid rgba(255,255,255,.4)', display:'flex', alignItems:'center', justifyContent:'center' }
      },
        student && student.photo_url
          ? React.createElement('img', { src:student.photo_url, alt:'photo', style:{width:'100%',height:'100%',objectFit:'cover'} })
          : React.createElement('div', { style:{fontSize:28, color:s.sidebar } }, '👤')
      ),
      React.createElement('div', { style:{fontSize:8, color:'rgba(255,255,255,.7)', textAlign:'center', lineHeight:1.3} },
        school.schoolName || 'School Name'
      )
    ),
    // Right content
    React.createElement('div', { style:{ flex:1, padding:'14px 14px', display:'flex', flexDirection:'column', justifyContent:'space-between' } },
      // Top
      React.createElement('div', null,
        React.createElement('div', { style:{ fontSize:7, fontWeight:700, color:s.sidebar, textTransform:'uppercase', letterSpacing:'.1em', marginBottom:2 } },
          'Student Identity Card'
        ),
        React.createElement('div', { style:{ fontSize:14, fontWeight:800, color:'#111827', lineHeight:1.2, marginBottom:6 } }, name ),
        React.createElement('div', { style:{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'3px 10px', fontSize:9 } },
          ...[
            ['Class',     student ? (student.class_name || student.cls || '—') : 'Class'],
            ['Section',   student ? (student.section_name || student.sec || '—') : 'Sec'],
            ['Adm No.',   student ? (student.admission_no || student.adm || '—') : 'ADM0001'],
            ['Roll No.',  student ? (student.roll_no || '—') : '—'],
            ['DOB',       student ? (student.date_of_birth || '—') : '—'],
            ['Blood Grp', student ? (student.blood_group || '—') : '—'],
          ].map(function(item) {
            return React.createElement('div', { key:item[0], style:{lineHeight:1.6} },
              React.createElement('span', { style:{ color:'#9CA3AF', fontSize:8 } }, item[0] + ': '),
              React.createElement('span', { style:{ color:'#374151', fontWeight:600 } }, item[1])
            );
          })
        )
      ),
      // Bottom
      React.createElement('div', {
        style:{ background:s.bg, borderRadius:7, padding:'5px 10px', display:'flex', justifyContent:'space-between', alignItems:'center' }
      },
        React.createElement('div', { style:{ fontSize:8, color:s.sidebar } },
          React.createElement('div', { style:{ fontWeight:700 } }, school.schoolName || 'School Name'),
          React.createElement('div', { style:{ color:'#6B7280', fontSize:7 } }, school.phone || '')
        ),
        React.createElement('div', { style:{ textAlign:'right', fontSize:7, color:s.sidebar } },
          React.createElement('div', null, 'Valid: 2025–26'),
          React.createElement('div', { style:{ marginTop:2, fontWeight:700, fontSize:9, color:s.accent } }, '✦ EduErpee')
        )
      )
    )
  );
}

export default function IDCard() {
  var reduxStudents = useSelector(function(s) { return s.admission.students; });
  var settings = React.useMemo(function() {
    try { return JSON.parse(localStorage.getItem('school_settings')) || {}; } catch { return {}; }
  }, []);

  var [search,    setSearch]    = useState('');
  var [selected,  setSelected]  = useState(null);
  var [cardStyle, setCardStyle] = useState('blue');
  var [students,  setStudents]  = useState([]);
  var [loading,   setLoading]   = useState(false);
  var [bulk,      setBulk]      = useState(false);
  var [bulkClass, setBulkClass] = useState('');

  // Load students from API
  var loadStudents = React.useCallback(async function(q) {
    setLoading(true);
    try {
      var res = await studentAPI.getAll({ search: q || undefined, limit: 50 });
      setStudents(res.data.data || []);
    } catch {
      // fallback to redux
      setStudents(reduxStudents.map(function(s) {
        return {
          id: s.id, admission_no: s.adm,
          first_name: s.name.split(' ')[0],
          last_name:  s.name.split(' ').slice(1).join(' '),
          class_name: s.cls, section_name: s.sec,
          parent_name: s.parent, parent_phone: s.phone,
          date_of_birth: s.dob, blood_group: s.blood, photo_url: null,
        };
      }));
    } finally { setLoading(false); }
  }, [reduxStudents]);

  React.useEffect(function() { loadStudents(''); }, []);

  var filtered = students.filter(function(s) {
    var q = search.toLowerCase();
    var name = ((s.first_name||'') + ' ' + (s.last_name||'')).toLowerCase();
    return !search || name.includes(q) || (s.admission_no||'').toLowerCase().includes(q) || (s.class_name||'').toLowerCase().includes(q);
  });

  var classes = Array.from(new Set(students.map(function(s) { return s.class_name; }).filter(Boolean)));

  function handlePrint() {
    if (!selected) { toast.error('Select a student first'); return; }
    var w = window.open('', '_blank', 'width=800,height=600');
    var cardHtml = document.getElementById('id-card-preview').innerHTML;
    w.document.write('<html><head><title>ID Card - ' + ((selected.first_name||'') + ' ' + (selected.last_name||'')).trim() + '</title>');
    w.document.write('<link rel="preconnect" href="https://fonts.googleapis.com"><link href="https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@400;600;700;800&display=swap" rel="stylesheet">');
    w.document.write('<style>@media print{@page{size:3.5in 2in;margin:0;}body{margin:0;padding:20px;font-family:"Plus Jakarta Sans",sans-serif;}}</style></head>');
    w.document.write('<body><div style="padding:20px;">' + cardHtml + '</div></body></html>');
    w.document.close();
    setTimeout(function() { w.print(); w.close(); }, 500);
    toast.success('Sending to printer…');
  }

  function handlePrintBulk() {
    var list = bulkClass ? students.filter(function(s) { return s.class_name === bulkClass; }) : students;
    if (!list.length) { toast.error('No students found'); return; }
    toast.success('Printing ' + list.length + ' ID cards…');
  }

  return React.createElement('div', null,
    // Header
    React.createElement('div', { style:{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:18} },
      React.createElement('div', null,
        React.createElement('h2', { style:{fontSize:20,fontWeight:700,color:'#111827'} }, '🪪 Student ID Card Generator'),
        React.createElement('p', { style:{fontSize:12,color:'#6B7280',marginTop:2} }, 'Design and print student identity cards')
      ),
      React.createElement('div', { style:{display:'flex',gap:10} },
        React.createElement('button', {
          onClick:function(){setBulk(true);},
          style:{padding:'9px 16px',border:'1.5px solid #1E1B4B',borderRadius:9,background:'#EDE9F8',color:'#1E1B4B',fontSize:12,fontWeight:700,cursor:'pointer'}
        }, '📄 Print All / Class'),
        selected ? React.createElement('button', {
          onClick:handlePrint,
          style:{padding:'9px 20px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:700,cursor:'pointer'}
        }, '🖨️ Print This Card') : null
      )
    ),

    React.createElement('div', { style:{display:'grid',gridTemplateColumns:'300px 1fr',gap:20} },

      // LEFT — student list + style picker
      React.createElement('div', null,
        // Style picker
        React.createElement('div', { style:{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:12,padding:14,marginBottom:14} },
          React.createElement('div', { style:{fontSize:12,fontWeight:700,color:'#374151',marginBottom:10} }, '🎨 Card Style'),
          React.createElement('div', { style:{display:'grid',gridTemplateColumns:'1fr 1fr',gap:8} },
            CARD_STYLES.map(function(s) {
              return React.createElement('div', {
                key: s.id,
                onClick: function() { setCardStyle(s.id); },
                style:{
                  padding:'8px 10px', borderRadius:9, cursor:'pointer',
                  border: '2px solid ' + (cardStyle===s.id?s.sidebar:'#E5E7EB'),
                  background: cardStyle===s.id?s.bg:'#F9FAFB',
                  display:'flex', alignItems:'center', gap:8
                }
              },
                React.createElement('div', { style:{width:14,height:14,borderRadius:'50%',background:s.sidebar,flexShrink:0} }),
                React.createElement('span', { style:{fontSize:11,fontWeight:600,color:'#374151'} }, s.name)
              );
            })
          )
        ),

        // Search
        React.createElement('div', { style:{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:12,overflow:'hidden'} },
          React.createElement('div', { style:{padding:'10px 12px',borderBottom:'0.5px solid #F3F4F6'} },
            React.createElement('input', {
              placeholder:'🔍 Search students…',
              value: search,
              onChange: function(e) { setSearch(e.target.value); },
              style:{width:'100%',padding:'8px 10px',border:'1.5px solid #E5E7EB',borderRadius:8,fontSize:12,outline:'none',boxSizing:'border-box'}
            })
          ),
          React.createElement('div', { style:{maxHeight:380,overflowY:'auto'} },
            loading
              ? React.createElement('div', { style:{padding:20,textAlign:'center',color:'#9CA3AF'} }, '⏳ Loading…')
              : filtered.length === 0
                ? React.createElement('div', { style:{padding:20,textAlign:'center',color:'#9CA3AF',fontSize:12} }, 'No students found')
                : filtered.map(function(s) {
                    var name = ((s.first_name||'') + ' ' + (s.last_name||'')).trim();
                    var isSelected = selected && selected.id === s.id;
                    return React.createElement('div', {
                      key: s.id,
                      onClick: function() { setSelected(s); },
                      style:{
                        padding:'10px 14px',
                        borderBottom:'0.5px solid #F9FAFB',
                        cursor:'pointer',
                        background: isSelected ? '#EDE9F8' : 'transparent',
                        borderLeft: isSelected ? '3px solid #7C3AED' : '3px solid transparent',
                        transition:'all .1s'
                      },
                      onMouseEnter: function(e) { if(!isSelected) e.currentTarget.style.background='#F5F3FF'; },
                      onMouseLeave: function(e) { if(!isSelected) e.currentTarget.style.background='transparent'; }
                    },
                      React.createElement('div', { style:{display:'flex',alignItems:'center',gap:9} },
                        s.photo_url
                          ? React.createElement('img', { src:s.photo_url, alt:'', style:{width:32,height:32,borderRadius:7,objectFit:'cover',flexShrink:0} })
                          : React.createElement('div', { style:{width:32,height:32,borderRadius:7,background:'#EDE9F8',display:'flex',alignItems:'center',justifyContent:'center',fontSize:12,fontWeight:700,color:'#1E1B4B',flexShrink:0} }, name[0]||'?'),
                        React.createElement('div', null,
                          React.createElement('div', { style:{fontSize:12,fontWeight:600,color:'#111827'} }, name),
                          React.createElement('div', { style:{fontSize:10,color:'#9CA3AF'} }, (s.admission_no||s.adm||'') + ' · ' + (s.class_name||s.cls||''))
                        )
                      )
                    );
                  })
          )
        )
      ),

      // RIGHT — card preview
      React.createElement('div', null,
        !selected
          ? React.createElement('div', { style:{background:'#fff',border:'2px dashed #E5E7EB',borderRadius:14,padding:60,textAlign:'center',color:'#9CA3AF'} },
              React.createElement('div', { style:{fontSize:48,marginBottom:12} }, '🪪'),
              React.createElement('div', { style:{fontSize:14,fontWeight:600,color:'#6B7280'} }, 'Select a student from the list'),
              React.createElement('div', { style:{fontSize:12,marginTop:4} }, 'to preview and print their ID card')
            )
          : React.createElement('div', null,
              // Student info bar
              React.createElement('div', { style:{background:'#EDE9F8',borderRadius:12,padding:'12px 16px',marginBottom:16,display:'flex',alignItems:'center',gap:12} },
                React.createElement('div', { style:{fontSize:20} }, '👤'),
                React.createElement('div', null,
                  React.createElement('div', { style:{fontWeight:700,color:'#1E1B4B'} }, ((selected.first_name||'') + ' ' + (selected.last_name||'')).trim()),
                  React.createElement('div', { style:{fontSize:12,color:'#6B7280'} }, (selected.admission_no||'') + ' · ' + (selected.class_name||selected.cls||'') + ' ' + (selected.section_name||selected.sec||''))
                ),
                React.createElement('div', { style:{marginLeft:'auto',fontSize:11,color:'#6B52B0'} },
                  selected.photo_url ? '✅ Photo uploaded' : '⚠️ No photo — placeholder shown'
                )
              ),

              // Card preview
              React.createElement('div', { style:{marginBottom:20} },
                React.createElement('div', { style:{fontSize:12,fontWeight:700,color:'#374151',marginBottom:10} }, 'Preview:'),
                React.createElement('div', { id:'id-card-preview', style:{display:'inline-block'} },
                  React.createElement(IDCardPreview, { student:selected, settings:settings, style:cardStyle })
                )
              ),

              // Back side
              React.createElement('div', { style:{marginBottom:20} },
                React.createElement('div', { style:{fontSize:12,fontWeight:700,color:'#374151',marginBottom:10} }, 'Back side:'),
                React.createElement('div', {
                  style:{width:340,height:200,borderRadius:14,border:'1px solid #E5E7EB',background:'#F9FAFB',display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',gap:8,fontSize:11,color:'#6B7280'}
                },
                  React.createElement('div', { style:{fontWeight:700,color:'#374151',fontSize:13} }, settings.schoolName || 'School Name'),
                  React.createElement('div', null, '📍 ' + (settings.address || 'School Address')),
                  React.createElement('div', null, '📞 ' + (settings.phone || 'Phone Number')),
                  React.createElement('div', null, '✉️ ' + (settings.email || 'Email Address')),
                  React.createElement('div', { style:{marginTop:8,padding:'6px 14px',background:'#EDE9F8',borderRadius:20,fontSize:10,color:'#1E1B4B',fontWeight:600} }, 'If found, please return to school')
                )
              ),

              // Action buttons
              React.createElement('div', { style:{display:'flex',gap:12} },
                React.createElement('button', { onClick:handlePrint, style:{flex:1,padding:'12px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:10,fontSize:13,fontWeight:700,cursor:'pointer'} }, '🖨️ Print ID Card'),
                React.createElement('button', {
                  onClick:function() { toast.success('Downloaded as PDF (feature coming soon)'); },
                  style:{padding:'12px 18px',border:'1.5px solid #1E1B4B',borderRadius:10,background:'#EDE9F8',color:'#1E1B4B',fontSize:13,fontWeight:700,cursor:'pointer'}
                }, '📥 Save PDF')
              )
            )
      )
    ),

    // Bulk print modal
    bulk ? React.createElement('div', { style:{position:'fixed',inset:0,background:'rgba(15,23,42,.45)',zIndex:500,display:'flex',alignItems:'center',justifyContent:'center',padding:20} },
      React.createElement('div', { style:{background:'#fff',borderRadius:18,width:440,overflow:'hidden'} },
        React.createElement('div', { style:{padding:'16px 20px',borderBottom:'0.5px solid #E5E7EB',display:'flex',justifyContent:'space-between',alignItems:'center'} },
          React.createElement('div', { style:{fontWeight:700,fontSize:15} }, '📄 Bulk Print ID Cards'),
          React.createElement('button', { onClick:function(){setBulk(false);}, style:{background:'#F3F4F6',border:'none',borderRadius:8,width:32,height:32,cursor:'pointer',fontSize:16} }, '✕')
        ),
        React.createElement('div', { style:{padding:20} },
          React.createElement('div', { style:{marginBottom:14} },
            React.createElement('label', { style:{display:'block',fontSize:11,fontWeight:700,color:'#4B5563',textTransform:'uppercase',marginBottom:6} }, 'Select Class (optional)'),
            React.createElement('select', {
              value: bulkClass,
              onChange: function(e) { setBulkClass(e.target.value); },
              style:{width:'100%',padding:'10px 12px',border:'1.5px solid #E5E7EB',borderRadius:9,fontSize:13,outline:'none'}
            },
              React.createElement('option', { value:'' }, 'All Classes (' + students.length + ' students)'),
              classes.map(function(c) {
                var cnt = students.filter(function(s) { return s.class_name === c; }).length;
                return React.createElement('option', { key:c, value:c }, c + ' (' + cnt + ' students)');
              })
            )
          ),
          React.createElement('div', { style:{padding:'10px 12px',background:'#FEF3C7',borderRadius:9,marginBottom:16,fontSize:12,color:'#92400E'} },
            '⚠️ Will print ' + (bulkClass ? students.filter(function(s){return s.class_name===bulkClass;}).length : students.length) + ' ID cards'
          ),
          React.createElement('div', { style:{display:'flex',gap:10,justifyContent:'flex-end'} },
            React.createElement('button', { onClick:function(){setBulk(false);}, style:{padding:'10px 16px',border:'1.5px solid #E5E7EB',borderRadius:9,background:'#fff',fontSize:13,cursor:'pointer'} }, 'Cancel'),
            React.createElement('button', { onClick:function(){handlePrintBulk();setBulk(false);}, style:{padding:'10px 20px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:700,cursor:'pointer'} }, '🖨️ Print Now')
          )
        )
      )
    ) : null
  );
}
